sql:
SELECT l.location_name, wd.precipitation
FROM locations l
JOIN weather_data wd ON l.location_id = wd.location_id
WHERE l.elevation = (
    SELECT MAX(elevation) FROM locations
);

SELECT weather_data.weather_id, locations.location_name, weather_data.temperature
FROM weather_data
INNER JOIN locations ON weather_data.location_id = locations.location_id;

SELECT l.location_name, ws.station_name
FROM locations l
JOIN weather_stations ws ON l.location_id = ws.location_id;

SELECT AVG(temperature) AS average_temperature
FROM weather_data
WHERE weather_text = 'cloudy';

external_knowledge:
- 'Participate in generating' refers to issuing forecasts and alerts;
- 'Resolve' means a user has completed the resolution of a forecast or alert they or others have issued;
- 'Most active countries' are those with the highest number of users participating;
- 'Indicators for whether all issued forecasts and alerts have been resolved' means checking if the total number of issued forecasts and alerts is equal to the number resolved.

sql:
SELECT l.location_name, a.alert_message
FROM alerts AS a
JOIN locations AS l ON a.location_id = l.location_id;

SELECT l.location_name, f.forecast_date, f.forecast_text, f.forecast_accuracy
FROM locations l
JOIN forecasts f ON l.location_id = f.location_id;

SELECT wind_direction_id, wind_direction_name 
FROM wind_directions 
WHERE wind_direction_name = 'south';
